import os
import logging

# Set up logging
logging.basicConfig(filename='cleanup_log.txt', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def confirm_update():
    """Check if the update is complete by looking for the update_completed file"""
    return os.path.exists('/root/update_completed')

def delete_temp_files(user_dir):
    """Delete all files with a.tmp extension in the given directory"""
    for root, dirs, files in os.walk(user_dir):
        for file in files:
            if file.endswith('.tmp'):
                try:
                    os.remove(os.path.join(root, file))
                except Exception as e:
                    logging.warning(f"Failed to delete {file}: {e}")

def main():
    user_dir = os.path.expanduser('~')
    if confirm_update():
        delete_temp_files(user_dir)
        print("Files with.tmp extension deleted successfully.")
    else:
        print("Update not complete. Cleanup cancelled.")

if __name__ == "__main__":
    main()
