import os
import psutil

def is_file_in_use(file_path):
    """Check if a file is in use by any process."""
    for proc in psutil.process_iter(['pid', 'open_files']):
        try:
            if proc.info['open_files']:
                for file in proc.info['open_files']:
                    if file.path == file_path:
                        return True
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass
    return False

def is_file_protected(file_path):
    """Check if a file is protected by the system's file permissions."""
    return not os.access(file_path, os.W_OK)

def delete_file(file_path):
    """Delete a file if it is not in use and not protected."""
    if not is_file_in_use(file_path) and not is_file_protected(file_path):
        try:
            os.remove(file_path)
            print(f"Deleted file: {file_path}")
        except PermissionError:
            print(f"Cannot delete file: {file_path} due to permission errors")

def traverse_folder(folder_path):
    """Recursively traverse a folder and its subdirectories."""
    for root, dirs, files in os.walk(folder_path):
        for file in files:
            file_path = os.path.join(root, file)
            delete_file(file_path)

if __name__ == "__main__":
    folder_path = input("Enter the path to the folder you want to clean: ")
    traverse_folder(folder_path)
